+	gitRepo := config.GetString("backup.git-repo")
+	if gitRepo != "" {
+		if strings.HasPrefix(gitRepo, "~/") {
+			home, _ := os.UserHomeDir()
+			gitRepo = filepath.Join(home, gitRepo[2:])
+		}
